isEqual.isEqual:
SELECT DISTINCT A.boardid BoardID, CASE #primary# WHEN '1' THEN A.boardname ELSE CASE WHEN (A.boardname2 = '' OR A.boardname2 IS NULL) THEN A.boardname ELSE A.boardname2 END END BoardName, A.treevieworder TreeViewOrder, A.boardcolor BoardColor, A.gubun, '' BoardGroupACL FROM TBL_Board_BoardInfo A JOIN (SELECT boardid , accessid , access_, tenant_id FROM TBL_Board_BoardManage WHERE TENANT_ID = #tenantID# AND parentboardid = #rootBoardID# AND access_ = 1 AND write_fg = 'true' AND boardid <> #excludeBoardID# AND accessid = #userID#
AND BoardGroupACL = 'Y'
) B ON A.TENANT_ID = B.TENANT_ID AND A.boardid = B.boardid WHERE A.TENANT_ID = #tenantID# AND (A.companyid = #companyID# OR TRIM(A.COMPANYID) = '' OR A.COMPANYID IS NULL) ORDER BY A.treevieworder ASC

